    // Define AmbiguousWidth regex (includes Greek, Cyrillic, some symbols, etc.)
    private static readonly Regex _ambigWidthRegex = new(
        """[\u00a1\u00a4\u00a7\u00a8\u00aa\u00ad\u00ae\u00b0-\u00b4\u00b6\u00b7\u00b8\u00ba\u00bc-\u00be\u00bf\u00c6\u00d0\u00d7\u00d8\u00de-\u00e1\u00e6\u00e8-\u00ea\u00ec-\u00ed\u00f0\u00f2-\u00f3\u00f7-\u00fa\u00fc\u00fe\u0101\u0111\u0113\u011b\u0126\u012b\u0131-\u0133\u0138\u013f\u0141\u0142\u0144\u0148\u0149\u014a\u014d\u0152\u0153\u0166\u0167\u016b\u01ce\u01d0\u01d2\u01d4\u01d6\u01d8\u01da\u01dc\u0251\u0261\u02c4\u02c7\u02c9-\u02cb\u02cd\u02d0\u02d8\u02d9\u02da\u02db\u02dd\u02df\u0300-\u036f\u0391-\u03a9\u03b1-\u03c9\u0401\u0410-\u044f\u0451\u2010\u2013-\u2016\u2018\u2019\u201c\u201d\u2020-\u2022\u2024-\u2027\u2030\u2032\u2033\u2035\u203b\u203e\u2074\u207f\u2081-\u2084\u20ac\u2103\u2105\u2109\u2113\u2116\u2121\u2122\u2126\u212b\u2153-\u2154\u215b-\u215e\u2160-\u216b\u2170-\u217b\u2189\u2190-\u2199\u21b8\u21b9\u21d2\u21d4\u21e7\u2200\u2202\u2203\u2207\u2208\u220b\u220f\u2211\u2215\u221a\u221d-\u221f\u2220\u2223\u2225\u2227-\u222c\u222e\u2234-\u2237\u223d\u2248\u224c\u2252\u2260\u2261\u2264\u2265\u2266\u2267\u226a\u226b\u226e\u226f\u2282\u2283\u2286\u2287\u2295\u2299\u22a5\u22bf\u22ee-\u22f1\u2312\u2460-\u24e9\u24eb-\u254b\u2550-\u2573\u2580-\u258f\u2592-\u2595\u25a0\u25a1\u25a3-\u25a9\u25b2\u25b3\u25b6\u25b7\u25bc\u25bd\u25c0\u25c1\u25c6-\u25c8\u25cb\u25ce-\u25d1\u25e2-\u25e5\u25ef\u2605\u2606\u2609\u260e\u260f\u2614\u2615\u261c\u261e\u2640\u2642\u2660\u2661\u2663-\u2665\u2667-\u266a\u266c-\u266d\u266f\u273d\u2776-\u277f\ue000-\uf8ff\ufe00-\ufe0f\ufffd]""",
        RegexOptions.Compiled
    );
    private static bool IsWideChar(char c)
    {
        return c >= 0x1100 &&
                 (c <= 0x115f || /* Hangul Jamo init. consonants */
                  c == 0x2329 || c == 0x232a ||
                  ((uint)(c - 0x2e80) <= (0xa4cf - 0x2e80) &&
                   c != 0x303f) || /* CJK ... Yi */
                  ((uint)(c - 0xac00) <= (0xd7a3 - 0xac00)) || /* Hangul Syllables */
                  ((uint)(c - 0xf900) <= (0xfaff - 0xf900)) || /* CJK Compatibility Ideographs */
                  ((uint)(c - 0xfe10) <= (0xfe19 - 0xfe10)) || /* Vertical forms */
                  ((uint)(c - 0xfe30) <= (0xfe6f - 0xfe30)) || /* CJK Compatibility Forms */
                  ((uint)(c - 0xff00) <= (0xff60 - 0xff00)) || /* Fullwidth Forms */
                  ((uint)(c - 0xffe0) <= (0xffe6 - 0xffe0)));
        // We can ignore these ranges because .Net strings use surrogate pairs
        // for this range and we do not handle surrogate pairs.
        // (c >= 0x20000 && c <= 0x2fffd) ||
        // (c >= 0x30000 && c <= 0x3fffd)
    }
    public static VisualElement[] GetVisualElements(string text)
    {
        if (string.IsNullOrEmpty(text)) { return []; }
        if (_cache.Get(text) is VisualElement[] cached) { return cached; }
        if (_pool.TryDequeue(out var list)) { list.Clear(); } else { list = []; }

        var parts = _ansiRegex.Split(text);
        foreach (var part in parts)
        {
            if (_ansiRegex.IsMatch(part))
            {
                if (_sgrRegex.IsMatch(part)) { list.Add(new VisualElement { Text = part, Width = 0 }); }
                continue;
            }
            var it = StringInfo.GetTextElementEnumerator(part);
            while (it.MoveNext())
            {
                var element = it.GetTextElement();
                if (_zwjSupported && list.Count > 0)
                {
                    var item = list[list.Count - 1];
                    var t = item.Text;
                    if (t.Length > 0 && t[t.Length - 1] == '\u200D' || element[0] == '\u200D')
                    {
                        item.Text += element;
                        list[list.Count - 1] = item;
                        continue;
                    }
                }
                if (!_zwjSupported && element.IndexOf('\u200D') >= 0)
                {
                    var emojiParts = element.Split('\u200D');
                    for (int i = 0; i < emojiParts.Length - 1; i++)
                    {
                        list.Add(new VisualElement { Text = emojiParts[i] + "\u200D", Width = 2 + _zwjWidth });
                    }
                    list.Add(new VisualElement { Text = emojiParts[emojiParts.Length - 1], Width = 2 });
                }
                else
                {
                    int width;
                    if (element.Length == 1 && IsWideChar(element[0]))
                    {
                        width = 2;
                    }
                    else if (element.IndexOf('\uFE0F') >= 0) // emoji with variation selector, treat as wide
                    {
                        width = 2;
                    }
                    else if (element.IndexOf('\uFE0E') >= 0) // emoji with text variation selector, treat as narrow
                    {
                        width = 1;
                    }
                    else if (_ambiguousAsWide && _ambigWidthRegex.IsMatch(element))
                    {
                        width = 2;
                    }
                    else if (_emojiRegex.IsMatch(element))
                    {
                        width = 2;
                    }
                    else
                    {
                        width = 1;
                    }
                    list.Add(new VisualElement { Text = element, Width = width });
                }
            }
        }

        var elements = list.ToArray();
        _pool.Enqueue(list);
        _cache.Set(text, elements, new CacheItemPolicy { SlidingExpiration = TimeSpan.FromMinutes(5) });
        return elements;
    }
    public static bool IsPureAscii(string text)
    {
        if (string.IsNullOrEmpty(text)) { return true; }
        for (var i = 0; i < text.Length; i++)
        {
            if (text[i] < ' ' || text[i] > '~')
            {
                return false;
            }
        }
        return true;
    }
    public static int GetVisualWidth(this string text)
    {
        if (string.IsNullOrEmpty(text)) { return 0; }
        if (IsPureAscii(text)) { return text.Length; }
        var elements = GetVisualElements(text);
        int totalWidth = 0;
        for (var i = 0; i < elements.Length; i++) { totalWidth += elements[i].Width; }
        return totalWidth;
    }
